import{_ as s,o as e,c as n,ai as i}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Nix","description":"","frontmatter":{"read_when":["你想要可复现、可回滚的安装","你已经在使用 Nix/NixOS/Home Manager","你想要所有内容都固定并以声明式管理"],"summary":"使用 Nix 声明式安装 OpenSoul","title":"Nix","x-i18n":{"generated_at":"2026-02-03T07:49:51Z","model":"claude-opus-4-5","provider":"pi","source_hash":"f1452194cfdd74613b5b3ab90b0d506eaea2d16b147497987710d6ad658312ba","source_path":"install/nix.md","workflow":15}},"headers":[],"relativePath":"zh-CN/install/nix.md","filePath":"zh-CN/install/nix.md","lastUpdated":1771906665000}'),l={name:"zh-CN/install/nix.md"};function p(t,a,o,r,c,d){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="nix-安装" tabindex="-1"><a class="header-anchor" href="#nix-安装">#</a> Nix 安装</h1><p>使用 Nix 运行 OpenSoul 的推荐方式是通过 <strong><a href="https://github.com/opensoul/nix-opensoul" target="_blank" rel="noreferrer">nix-opensoul</a></strong> — 一个开箱即用的 Home Manager 模块。</p><h2 id="快速开始" tabindex="-1"><a class="header-anchor" href="#快速开始">#</a> 快速开始</h2><p>将此粘贴给你的 AI 智能体（Claude、Cursor 等）：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I want to set up nix-opensoul on my Mac.</span></span>
<span class="line"><span>Repository: github:opensoul/nix-opensoul</span></span>
<span class="line"><span></span></span>
<span class="line"><span>What I need you to do:</span></span>
<span class="line"><span>1. Check if Determinate Nix is installed (if not, install it)</span></span>
<span class="line"><span>2. Create a local flake at ~/code/opensoul-local using templates/agent-first/flake.nix</span></span>
<span class="line"><span>3. Help me create a Telegram bot (@BotFather) and get my chat ID (@userinfobot)</span></span>
<span class="line"><span>4. Set up secrets (bot token, Anthropic key) - plain files at ~/.secrets/ is fine</span></span>
<span class="line"><span>5. Fill in the template placeholders and run home-manager switch</span></span>
<span class="line"><span>6. Verify: launchd running, bot responds to messages</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Reference the nix-opensoul README for module options.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><blockquote><p><strong>📦 完整指南：<a href="https://github.com/opensoul/nix-opensoul" target="_blank" rel="noreferrer">github.com/opensoul/nix-opensoul</a></strong></p><p>nix-opensoul 仓库是 Nix 安装的权威来源。本页只是一个快速概述。</p></blockquote><h2 id="你将获得" tabindex="-1"><a class="header-anchor" href="#你将获得">#</a> 你将获得</h2><ul><li>Gateway 网关 + macOS 应用 + 工具（whisper、spotify、cameras）— 全部固定版本</li><li>重启后仍能运行的 Launchd 服务</li><li>带有声明式配置的插件系统</li><li>即时回滚：<code>home-manager switch --rollback</code></li></ul><hr><h2 id="nix-模式运行时行为" tabindex="-1"><a class="header-anchor" href="#nix-模式运行时行为">#</a> Nix 模式运行时行为</h2><p>当设置 <code>OPENSOUL_NIX_MODE=1</code> 时（nix-opensoul 会自动设置）：</p><p>OpenSoul 支持 <strong>Nix 模式</strong>，使配置确定性并禁用自动安装流程。 通过导出以下环境变量启用：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_NIX_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>在 macOS 上，GUI 应用不会自动继承 shell 环境变量。你也可以通过 defaults 启用 Nix 模式：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">defaults</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> write</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ai.opensoul.mac</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opensoul.nixMode</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -bool</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="配置-状态路径" tabindex="-1"><a class="header-anchor" href="#配置-状态路径">#</a> 配置 + 状态路径</h3><p>OpenSoul 从 <code>OPENSOUL_CONFIG_PATH</code> 读取 JSON5 配置，并将可变数据存储在 <code>OPENSOUL_STATE_DIR</code> 中。</p><ul><li><code>OPENSOUL_STATE_DIR</code>（默认：<code>~/.opensoul</code>）</li><li><code>OPENSOUL_CONFIG_PATH</code>（默认：<code>$OPENSOUL_STATE_DIR/opensoul.json</code>）</li></ul><p>在 Nix 下运行时，将这些显式设置为 Nix 管理的位置，以便运行时状态和配置不会进入不可变存储。</p><h3 id="nix-模式下的运行时行为" tabindex="-1"><a class="header-anchor" href="#nix-模式下的运行时行为">#</a> Nix 模式下的运行时行为</h3><ul><li>自动安装和自我修改流程被禁用</li><li>缺失的依赖会显示 Nix 特定的修复消息</li><li>存在时 UI 会显示只读 Nix 模式横幅</li></ul><h2 id="打包注意事项-macos" tabindex="-1"><a class="header-anchor" href="#打包注意事项-macos">#</a> 打包注意事项（macOS）</h2><p>macOS 打包流程期望在以下位置有一个稳定的 Info.plist 模板：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>apps/macos/Sources/OpenSoul/Resources/Info.plist</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><a href="https://github.com/NJX-njx/opensoul/blob/main/scripts/package-mac-app.sh" target="_blank" rel="noreferrer"><code>scripts/package-mac-app.sh</code></a> 将此模板复制到应用包中并修补动态字段（bundle ID、版本/构建号、Git SHA、Sparkle 密钥）。这使 plist 对于 SwiftPM 打包和 Nix 构建保持确定性（它们不依赖完整的 Xcode 工具链）。</p><h2 id="相关内容" tabindex="-1"><a class="header-anchor" href="#相关内容">#</a> 相关内容</h2><ul><li><a href="https://github.com/opensoul/nix-opensoul" target="_blank" rel="noreferrer">nix-opensoul</a> — 完整设置指南</li><li><a href="/docs/start/wizard">向导</a> — 非 Nix CLI 设置</li><li><a href="/docs/install/docker">Docker</a> — 容器化设置</li></ul>`,27)])])}const b=s(l,[["render",p]]);export{u as __pageData,b as default};
